// Tiny Express server with a deliberately small API surface.
const crypto = require('node:crypto');
const express = require('express');
const fs = require('node:fs');
const path = require('node:path');

const app = express();
app.use(express.json({ verify: (req, _res, buffer) => { req.rawBody = buffer; } }));

const items = [
  { id: 1, name: 'alpha', qty: 3 },
  { id: 2, name: 'beta', qty: 5 },
];
const webhookSecret = fs.readFileSync(path.join(__dirname, '..', 'data', 'webhook-secret.txt'), 'utf8').trim();
const acceptedWebhookIds = new Set();

app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });
});

app.get('/items', (_req, res) => {
  res.json({ items });
});

app.get('/items/:id', (req, res) => {
  const id = Number(req.params.id);
  const item = items.find((it) => it.id === id);
  if (!item) {
    res.status(404).json({ error: 'not_found', id });
    return;
  }
  res.json({ item });
});

app.post('/webhook', (req, res) => {
  const rawBody = req.rawBody || Buffer.alloc(0);
  const expectedSignature = crypto.createHmac('sha256', webhookSecret).update(rawBody).digest('hex');
  const receivedSignature = req.get('X-Signature') || '';
  const expectedBuffer = Buffer.from(expectedSignature, 'utf8');
  const receivedBuffer = Buffer.from(receivedSignature, 'utf8');

  if (expectedBuffer.length !== receivedBuffer.length || !crypto.timingSafeEqual(expectedBuffer, receivedBuffer)) {
    res.status(401).json({ error: 'invalid_signature' });
    return;
  }

  const { id, type, timestamp, data } = req.body || {};
  if (
    typeof id !== 'string' || id.length === 0 ||
    typeof type !== 'string' || type.length === 0 ||
    typeof timestamp !== 'number' ||
    typeof data !== 'object' || data === null || Array.isArray(data)
  ) {
    res.status(400).json({ error: 'invalid_body' });
    return;
  }

  if (acceptedWebhookIds.has(id)) {
    res.status(409).json({ error: 'duplicate_event', id });
    return;
  }

  acceptedWebhookIds.add(id);
  res.json({ accepted: true, id });
});

if (require.main === module) {
  const port = Number(process.env.PORT) || 3000;
  app.listen(port, () => {
    console.log(`harbor-tools server listening on :${port}`);
  });
}

module.exports = { app };

